// MT5Server is the server API for MT5 service.
// All implementations must embed UnimplementedMT5Server
// for forward compatibility.
type MT5Server interface {
	// Accound details
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5"
	//	}
	Account(context.Context, *AccountRequest) (*AccountReply, error)
	// Balance, Equity, Currency, FreeMargin, Margin, MarginLevel, Profit, Leverage, Credit
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5"
	//	}
	AccountSummary(context.Context, *AccountSummaryRequest) (*AccountSummaryReply, error)
	// List of opened orders
	// [Example]
	// {
	//
	//	 "id": "",
	//	 "sort": "OpenTime",
	//	 "ascending": "True"
	//	}
	OpenedOrders(context.Context, *OpenedOrdersRequest) (*OpenedOrdersReply, error)
	// List of opened orders
	// [Example]
	// {
	//
	//	 "id": "",
	//	 "ticket": ""
	//	}
	OpenedOrder(context.Context, *OpenedOrderRequest) (*OpenedOrderReply, error)
	// Just tickets of opened orders
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt4"
	//	}
	OpenedOrdersTickets(context.Context, *OpenedOrdersTicketsRequest) (*OpenedOrdersTicketsReply, error)
	// Order history
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5",
	//	 "from": "2022-01-01T00:00:00",
	//	 "to": "2022-09-01T00:00:00",
	//	 "sort": "OpenTime",
	//	 "ascending": "True"
	//	}
	OrderHistory(context.Context, *OrderHistoryRequest) (*OrderHistoryReply, error)
	// Pending order history
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5",
	//	 "from": "2023-09-01T00:00:00",
	//	 "to": "2023-10-01T00:00:00",
	//	 "ascending": "True"
	//	}
	PendingOrderHistory(context.Context, *PendingOrderHistoryRequest) (*PendingOrderHistoryReply, error)
	// Order history
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5",
	//	 "from": "2022-01-01T00:00:00",
	//	 "to": "2022-09-01T00:00:00",
	//	 "ordersPerPage": "10",
	//	 "pageNumber": "0",
	//	 "requestAgain": "False",
	//	 "sort": "OpenTime",
	//	 "ascending": "True",
	//	 "ignoreDepositWithdraw": "False"
	//	}
	OrderHistoryPagination(context.Context, *OrderHistoryPaginationRequest) (*OrderHistoryPaginationReply, error)
	// List of avaliable symbols with parameters
	// [Example]
	// {
	//
	//	 "id": ""
	//	}
	Symbols(context.Context, *SymbolsRequest) (*SymbolsReply, error)
	// List of avaliable symbols
	// [Example]
	// {
	//
	//	 "id": ""
	//	}
	SymbolList(context.Context, *SymbolListRequest) (*SymbolListReply, error)
	// Lot of informationabout about acocount. Can stuck swagger because of long json. You can use filter to reduce data.
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5",
	//	 "symbol": "EURUSD",
	//	 "msNotOlder": "0"
	//	}
	GetQuote(context.Context, *GetQuoteRequest) (*GetQuoteReply, error)
	// Latest quote for the specified symbol
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5",
	//	 "msNotOlder": "0"
	//	}
	GetQuoteMany(context.Context, *GetQuoteManyRequest) (*GetQuoteManyReply, error)
	// Market Watch for the specified symbols
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5"
	//	}
	MarketWatchMany(context.Context, *MarketWatchManyRequest) (*MarketWatchManyReply, error)
	// Full infromation about symbol and his group
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5",
	//	 "symbol": "EURUSD"
	//	}
	SymbolParams(context.Context, *SymbolParamsRequest) (*SymbolParamsReply, error)
	// Full infromation about symbol and his group for several symbols
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5",
	//	 "limit": "10000"
	//	}
	SymbolParamsMany(context.Context, *SymbolParamsManyRequest) (*SymbolParamsManyReply, error)
	// Quote and trade sessions(open and close time) for the symbol. Returns 2 arrays. One for quotes and one for trades. Each array contains 7 elements for each day of weeks starting from Sunday.
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5",
	//	 "symbol": "EURUSD"
	//	}
	SymbolSessionsEx(context.Context, *SymbolSessionsExRequest) (*SymbolSessionsExReply, error)
	// Quote and trade sessions(open and close time) for the symbol. Returns 2 arrays. One for quotes and one for trades. Each array contains 7 elements for each day of weeks starting from Sunday.
	// <br> [Example] <br>
	// { <br>
	//
	//	 "id": "demo-token-mt5" <br>
	//	}
	SymbolSessionsExMany(context.Context, *SymbolSessionsExManyRequest) (*SymbolSessionsExManyReply, error)
	// Server timezone.
	// [Example]
	// {
	//
	//	 "id": ""
	//	}
	ServerTimezone(context.Context, *ServerTimezoneRequest) (*ServerTimezoneReply, error)
	// Check market open or not for specified symbol.
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5",
	//	 "symbol": "EURUSD"
	//	}
	IsTradeSession(context.Context, *IsTradeSessionRequest) (*IsTradeSessionReply, error)
	// Check market open or not for specified symbol.
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5"
	//	}
	IsTradeSessionMany(context.Context, *IsTradeSessionManyRequest) (*IsTradeSessionManyReply, error)
	// Check market open or not for specified symbol.
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5",
	//	 "symbol": "EURUSD"
	//	}
	IsQuoteSession(context.Context, *IsQuoteSessionRequest) (*IsQuoteSessionReply, error)
	// Check market open or not for specified symbol.
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5"
	//	}
	IsQuoteSessionMany(context.Context, *IsQuoteSessionManyRequest) (*IsQuoteSessionManyReply, error)
	// Tick value.
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5"
	//	}
	GetTickValueMany(context.Context, *GetTickValueManyRequest) (*GetTickValueManyReply, error)
	// Tick value with size.
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5"
	//	}
	TickValueWithSize(context.Context, *TickValueWithSizeRequest) (*TickValueWithSizeReply, error)
	ChangePassword(context.Context, *ChangePasswordRequest) (*ChangePasswordReply, error)
	// Mail inbox
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5"
	//	}
	Mails(context.Context, *MailsRequest) (*MailsReply, error)
	// Required margin
	// [Example]
	// {
	//
	//	 "id": "demo-token-mt5",
	//	 "symbol": "EURUSD",
	//	 "lots": "1",
	//	 "type": "DealBuy",
	//	 "price": "0"
	//	}
	RequiredMargin(context.Context, *RequiredMarginRequest) (*RequiredMarginReply, error)
	mustEmbedUnimplementedMT5Server()
}

